import{_ as t,a}from"./chunks/填写github渠道配置.B-S0-llS.js";import{_ as l,o as s,c as d,a2 as r}from"./chunks/framework.DnrXFDHb.js";const _=JSON.parse('{"title":"GitHub Releases チャンネルの追加","description":"","frontmatter":{},"headers":[],"relativePath":"ja-JP/upload/github-releases.md","filePath":"ja-JP/upload/github-releases.md","lastUpdated":1781962217000}'),i={name:"ja-JP/upload/github-releases.md"};function o(n,e,h,b,u,c){return s(),d("div",null,[...e[0]||(e[0]=[r('<h1 id="github-releases-チャンネルの追加" tabindex="-1">GitHub Releases チャンネルの追加 <a class="header-anchor" href="#github-releases-チャンネルの追加" aria-label="Permalink to &quot;GitHub Releases チャンネルの追加&quot;">​</a></h1><p>GitHub Releases チャンネルは、GitHub リポジトリの Release Assets を保存先として利用します。</p><h2 id="向いているケース" tabindex="-1">向いているケース <a class="header-anchor" href="#向いているケース" aria-label="Permalink to &quot;向いているケース&quot;">​</a></h2><ul><li>既に GitHub をよく使っている。</li><li>小規模な画像や配布ファイルを Release Assets に置きたい。</li><li>GitHub Token で管理できる保存先を増やしたい。</li></ul><h2 id="事前に用意するもの" tabindex="-1">事前に用意するもの <a class="header-anchor" href="#事前に用意するもの" aria-label="Permalink to &quot;事前に用意するもの&quot;">​</a></h2><table tabindex="0"><thead><tr><th>必要なもの</th><th>用途</th></tr></thead><tbody><tr><td>GitHub アカウント</td><td>リポジトリと Token を管理します</td></tr><tr><td>リポジトリ</td><td>Release を置く場所</td></tr><tr><td>Personal Access Token</td><td>Release Assets へアップロードする権限</td></tr><tr><td>Release タグ</td><td>Assets を紐付ける Release</td></tr></tbody></table><h2 id="token-権限" tabindex="-1">Token 権限 <a class="header-anchor" href="#token-権限" aria-label="Permalink to &quot;Token 権限&quot;">​</a></h2><p>GitHub の Personal Access Token には、対象リポジトリの Release を操作できる権限が必要です。</p><p><img src="'+t+'" alt="GitHub 権限" loading="lazy"></p><p>プライベートリポジトリを使う場合は、プライベートリポジトリへのアクセス権も付けてください。</p><h2 id="imgbed-へ入力する" tabindex="-1">ImgBed へ入力する <a class="header-anchor" href="#imgbed-へ入力する" aria-label="Permalink to &quot;ImgBed へ入力する&quot;">​</a></h2><p>アップロード設定で <code>GitHub Releases</code> を選びます。</p><table tabindex="0"><thead><tr><th>項目</th><th>入力内容</th></tr></thead><tbody><tr><td>チャンネル名</td><td>例：<code>GitHub Release</code></td></tr><tr><td>Owner</td><td>リポジトリ所有者</td></tr><tr><td>Repo</td><td>リポジトリ名</td></tr><tr><td>Token</td><td>GitHub Personal Access Token</td></tr><tr><td>Release Tag</td><td>Assets を置く Release タグ</td></tr><tr><td>保存パス</td><td>任意</td></tr></tbody></table><p><img src="'+a+'" alt="GitHub 設定" loading="lazy"></p><h2 id="確認方法" tabindex="-1">確認方法 <a class="header-anchor" href="#確認方法" aria-label="Permalink to &quot;確認方法&quot;">​</a></h2><ol><li>保存後にチャンネルカードが表示される。</li><li>テスト画像をアップロードする。</li><li>対象リポジトリの Release Assets にファイルが追加される。</li><li>返されたリンクが開ける。</li></ol><h2 id="注意点" tabindex="-1">注意点 <a class="header-anchor" href="#注意点" aria-label="Permalink to &quot;注意点&quot;">​</a></h2><ul><li>GitHub Releases は大量ファイルや大容量配信に向いた専用ストレージではありません。</li><li>Token の権限は対象リポジトリに絞ると安全です。</li><li>Release や Assets を手動で削除すると、ImgBed 側のリンクが開けなくなることがあります。</li></ul>',18)])])}const R=l(i,[["render",o]]);export{_ as __pageData,R as default};
